import clsx from 'clsx';
import type { JSX } from 'react';

import { customSymbol, customSymbolLarge } from './seriesSymbol.sty.js';
import { ShapeIcon } from '../../../shape/ShapeIcon.js';
import { VariantShape } from '../../../shape/type.js';
import type { IconStyle } from '../../types/series.js';

export const SeriesSymbol = (props: {
  color?: string;
  shape?: VariantShape;
  symbol?: string;
  icon?: JSX.Element;
  iconStyle?: IconStyle;
}) => {
  if (props.icon) {
    return (
      <span
        aria-hidden="true"
        className={clsx(
          customSymbol,
          props.iconStyle === 'large' && customSymbolLarge,
        )}
      >
        {props.icon}
      </span>
    );
  }

  if (props.symbol && props.symbol.trim() !== '') {
    return (
      <span
        className={clsx(
          customSymbol,
          props.iconStyle === 'large' && customSymbolLarge,
        )}
        aria-hidden="true"
      >
        {props.symbol}
      </span>
    );
  }

  if (!props.color) {
    return null;
  }

  return <ShapeIcon color={props.color} shape={props.shape || 'single'} />;
};
